import{_ as i,o as a,c as t,ac as n}from"./chunks/framework.DnBnwVZk.js";const o=JSON.parse('{"title":"计算机中的位运算与编码","description":"","frontmatter":{"date":"2017-05-14T00:00:00.000Z","categories":["知识&技巧"],"tags":["Encode"],"publish":true},"headers":[],"relativePath":"views/basic/EncodeInt.md","filePath":"views/basic/EncodeInt.md","lastUpdated":1775654397000}'),e={name:"views/basic/EncodeInt.md"};function l(h,s,p,k,r,d){return a(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1494720000000"},[...s[0]||(s[0]=[n('<h1 id="计算机中的位运算与编码" tabindex="-1">计算机中的位运算与编码 <a class="header-anchor" href="#计算机中的位运算与编码" aria-label="Permalink to &quot;计算机中的位运算与编码&quot;">​</a></h1><h2 id="运算符-对一个表达式执行位非运算" tabindex="-1">~运算符 对一个表达式执行位非运算 <a class="header-anchor" href="#运算符-对一个表达式执行位非运算" aria-label="Permalink to &quot;~运算符 对一个表达式执行位非运算&quot;">​</a></h2><ul><li>运算规则为被运算数按位取反，</li><li>由于实际存储使用的为数字的补码，实际上是补码按位取反</li><li>console.log的时候，打印的为原码</li></ul><h2 id="常用于判断字符串是否存在" tabindex="-1">~常用于判断字符串是否存在 <a class="header-anchor" href="#常用于判断字符串是否存在" aria-label="Permalink to &quot;~常用于判断字符串是否存在&quot;">​</a></h2><p>因为~0=-1 且~-1=0,所以string.indexOf(&#39;str&#39;)为-1时，~string.indexOf(&#39;str&#39;)为0，所以 if(~string.indexOf(&#39;str&#39;))等同于if(string.indexOf(&#39;str&#39;)!=-1)</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> whole </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;this is a sample string&#39;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> str </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;sample&#39;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whole.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">indexOf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(str)) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whole</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}包含${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">str</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">`${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">whole</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}不包含${</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">str</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 输出 this is a sample string包含sample</span></span></code></pre></div><h2 id="原码、反码与补码" tabindex="-1">原码、反码与补码 <a class="header-anchor" href="#原码、反码与补码" aria-label="Permalink to &quot;原码、反码与补码&quot;">​</a></h2><blockquote><p>有符号数的最高位仅表示正负，不存储数据 即假设数字使用8bit存储（1Byte)，实际存储数字的为7bit，可表示值-(2^7^-1)~2^7^,即-127~128</p></blockquote><h3 id="正数的原码、反码与补码一致" tabindex="-1">正数的原码、反码与补码一致 <a class="header-anchor" href="#正数的原码、反码与补码一致" aria-label="Permalink to &quot;正数的原码、反码与补码一致&quot;">​</a></h3><p>0 原码：00000000 反码：00000000 补码：00000000</p><h3 id="负数的原码-最高位1-其他位是绝对值的二进制-反码-原码最高为不变-其他位按位取反-补码-反码-1-即原码的最高位不变-其他位按位取反加1" tabindex="-1">负数的原码：最高位1，其他位是绝对值的二进制，反码：原码最高为不变，其他位按位取反，补码：反码+1，即原码的最高位不变，其他位按位取反加1 <a class="header-anchor" href="#负数的原码-最高位1-其他位是绝对值的二进制-反码-原码最高为不变-其他位按位取反-补码-反码-1-即原码的最高位不变-其他位按位取反加1" aria-label="Permalink to &quot;负数的原码：最高位1，其他位是绝对值的二进制，反码：原码最高为不变，其他位按位取反，补码：反码+1，即原码的最高位不变，其他位按位取反加1&quot;">​</a></h3><p>-1 原码：10000001 反码：11111110 补码：11111111</p><h3 id="_0的运算过程" tabindex="-1">~0的运算过程 <a class="header-anchor" href="#_0的运算过程" aria-label="Permalink to &quot;~0的运算过程&quot;">​</a></h3><p>0的补码 00000000 按位取反 11111111 获得11111111的原码： 高位为1表示此补码为负数的补码，则获取原码为-1按位取反 即 11111111 -1 11111110 取反 10000001 即为-1 所以console.log(~0) // -1</p>',14)])])}const c=i(e,[["render",l]]);export{o as __pageData,c as default};
